// Extract token ID from market details for pricing
const market = $input.first().json;

let clobTokenIds = market.clobTokenIds || [];
if (typeof clobTokenIds === 'string') {
  try { clobTokenIds = JSON.parse(clobTokenIds); } catch(e) { clobTokenIds = []; }
}

let tokens = market.tokens || [];
if (typeof tokens === 'string') {
  try { tokens = JSON.parse(tokens); } catch(e) { tokens = []; }
}

const firstTokenId = (tokens[0] && tokens[0].tokenId) || clobTokenIds[0] || '';

return [{
  json: {
    question: market.question || market.title || 'Unknown',
    conditionId: market.conditionId || '',
    slug: market.slug || '',
    volume: market.volume || 0,
    tokenId: firstTokenId,
    description: market.description || ''
  }
}];

// Assess liquidity from order book depth and prepare AI prompt
const priceData = $input.first().json;
const marketData = $('Extract Token ID').first().json;

const currentPrice = Number(priceData.price || priceData.midpoint || 0.5);
const orderBook = priceData.orderBook || {};

// Calculate liquidity metrics
const bids = orderBook.bids || [];
const asks = orderBook.asks || [];
const bidDepth = bids.reduce((sum, b) => sum + Number(b.size || b[1] || 0), 0);
const askDepth = asks.reduce((sum, a) => sum + Number(a.size || a[1] || 0), 0);
const totalLiquidity = bidDepth + askDepth;

// Best bid/ask for spread calculation
const bestBid = bids.length > 0 ? Number(bids[0].price || bids[0][0] || 0) : 0;
const bestAsk = asks.length > 0 ? Number(asks[0].price || asks[0][0] || 0) : 0;
const spread = bestAsk > 0 && bestBid > 0 ? (bestAsk - bestBid) : 0;

return [{
  json: {
    question: marketData.question,
    description: marketData.description,
    conditionId: marketData.conditionId,
    slug: marketData.slug,
    tokenId: marketData.tokenId,
    currentPrice,
    totalLiquidity,
    bidDepth,
    askDepth,
    spread: spread.toFixed(3),
    bestBid: bestBid.toFixed(3),
    bestAsk: bestAsk.toFixed(3)
  }
}];

// Parse AI response and calculate edge
const aiRaw = $input.first().json;
const marketData = $('Assess Liquidity').first().json;

let text = '';
try {
  text = aiRaw.choices[0].message.content || '';
} catch(e) {
  text = JSON.stringify(aiRaw);
}

let analysis = { fair_price: 0.5, confidence: 0, reasoning: 'Could not parse AI response' };
try {
  const jsonMatch = text.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    analysis = JSON.parse(jsonMatch[0]);
  }
} catch(e) {
  // Keep defaults
}

const fairPrice = Number(analysis.fair_price) || 0.5;
const confidence = Number(analysis.confidence) || 0;
const edge = fairPrice - marketData.currentPrice;
const edgePercent = Math.abs(edge * 100);
const direction = edge > 0 ? 'BUY' : 'SELL';

return [{
  json: {
    fairPrice: fairPrice.toFixed(3),
    confidence,
    reasoning: analysis.reasoning || '',
    edge: edge.toFixed(3),
    edgePercent: edgePercent.toFixed(1),
    direction,
    currentPrice: marketData.currentPrice,
    question: marketData.question,
    slug: marketData.slug,
    tokenId: marketData.tokenId,
    totalLiquidity: marketData.totalLiquidity,
    spread: marketData.spread,
    meetsThreshold: edgePercent > 10 && confidence > 0.7
  }
}];

